import React, { useEffect, useState } from "react";
import { Container, Table, Button, Form, Card, Modal, Spinner } from "react-bootstrap";
import { toast } from "react-toastify";
import api from "../services/api";

function Medications() {
  const [medications, setMedications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [form, setForm] = useState({ 
    name: "", 
    dosage: "", 
    frequency: "" 
  });

  useEffect(() => {
    fetchMedications();
  }, []);

  const fetchMedications = async () => {
    try {
      const res = await api.get("/api/medications");
      setMedications(res.data);
    } catch (err) {
      console.error("Fetch medications error:", err);
      toast.error("Failed to load medications");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!form.name || !form.dosage || !form.frequency) {
      toast.error("All fields are required");
      return;
    }

    setSubmitting(true);

    try {
      await api.post("/api/medications", form);
      toast.success("Medication added successfully");
      setForm({ name: "", dosage: "", frequency: "" });
      setShowModal(false);
      fetchMedications();
    } catch (err) {
      console.error("Add medication error:", err);
      toast.error(err.response?.data?.error || "Failed to add medication");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this medication?")) {
      return;
    }

    try {
      await api.delete(`/api/medications/${id}`);
      toast.success("Medication deleted");
      fetchMedications();
    } catch (err) {
      console.error("Delete medication error:", err);
      toast.error("Failed to delete medication");
    }
  };

  if (loading) {
    return (
      <Container className="mt-4 text-center">
        <Spinner animation="border" variant="primary" />
        <p className="mt-2">Loading medications...</p>
      </Container>
    );
  }

  return (
    <Container className="mt-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2>
            <i className="bi bi-capsule me-2"></i>
            Your Medications
          </h2>
          <p className="text-muted">Track your medications and dosages</p>
        </div>
        <Button variant="primary" onClick={() => setShowModal(true)}>
          <i className="bi bi-plus-circle me-2"></i>
          Add Medication
        </Button>
      </div>

      {medications.length === 0 ? (
        <Card className="text-center p-5">
          <i className="bi bi-capsule text-muted" style={{ fontSize: "3rem" }}></i>
          <h4 className="mt-3">No medications yet</h4>
          <p className="text-muted">Start tracking your medications</p>
          <Button variant="primary" onClick={() => setShowModal(true)}>
            Add First Medication
          </Button>
        </Card>
      ) : (
        <Table striped bordered hover responsive>
          <thead className="table-dark">
            <tr>
              <th>Medication</th>
              <th>Dosage</th>
              <th>Frequency</th>
              <th>Added</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {medications.map((med) => (
              <tr key={med.id}>
                <td><strong>{med.name}</strong></td>
                <td>{med.dosage}</td>
                <td>{med.frequency}</td>
                <td>{new Date(med.created_at).toLocaleDateString()}</td>
                <td>
                  <Button
                    variant="danger"
                    size="sm"
                    onClick={() => handleDelete(med.id)}
                  >
                    <i className="bi bi-trash"></i>
                  </Button>
                </td>
              </tr>
            ))}
          </tbody>
        </Table>
      )}

      {/* Add Medication Modal */}
      <Modal show={showModal} onHide={() => setShowModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Add New Medication</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleSubmit}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label>Medication Name</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., Ibuprofen"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Dosage</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., 200mg"
                value={form.dosage}
                onChange={(e) => setForm({ ...form, dosage: e.target.value })}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Frequency</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., Twice daily"
                value={form.frequency}
                onChange={(e) => setForm({ ...form, frequency: e.target.value })}
                required
              />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setShowModal(false)} disabled={submitting}>
              Cancel
            </Button>
            <Button variant="primary" type="submit" disabled={submitting}>
              {submitting ? "Adding..." : "Add Medication"}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </Container>
  );
}

export default Medications;
